        __m256d ar = LD(&in_re[k]), ai = LD(&in_im[k]);
        __m256d br = LD(&in_re[K+k]), bi = LD(&in_im[K+k]);
        ST(&out_re[k],_mm256_add_pd(ar,br));
        ST(&out_im[k],_mm256_add_pd(ai,bi));
        ST(&out_re[K+k],_mm256_sub_pd(ar,br));
